var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"구멍… 아니, 우물에서 갑자기 빛이 솟아났다고?","JPN":"穴……じゃなくて、井戸から突然光が溢れた？","ENG":"A light suddenly shot out of the hole… I mean, well?","TWN":"那個洞…不對，井裡突然發出光？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"갑자기가 아니다. 내가 도착하기 전부터 그렇게 빛나는 채였어.","JPN":"突然じゃない。私が着く前からそうなっていた。","ENG":"It wasn't sudden. It was like that before I even got there.","TWN":"不是突然。我到的時候就已經是那樣了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아쉽게도, 너희들이 오는 사이에 사라졌지만.","JPN":"残念ながら、お前たちが来る途中に消えてしまったが。","ENG":"Unfortunately, it vanished while you two were on your way.","TWN":"可惜，你們來的路上，光芒就消失了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사진은? 내가 준 폰으로 안 찍어뒀어?","JPN":"写真は？　私が渡した携帯で撮ってないの？","ENG":"What about a photo? Didn't you take one with the phone I gave you?","TWN":"照片呢？你沒用我給你的手機拍下來嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"보다시피 고장 났다. 전화를 걸자마자 바로 먹통이 되더군.","JPN":"見てのとおり壊れた。電話をかけた途端使えなくなった。","ENG":"As you can see, it's broken. The moment I tried to call, it just went dead.","TWN":"你看，壞掉了。打電話一接通，馬上就沒訊號了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"윽, 또야? 어쩐지 받기도 전에 끊어버리더라.","JPN":"げっ、また？　どうりで出る前に切れるわけだよ……","ENG":"Ugh, again? I knew something was up when it hung up before I could even pick up.","TWN":"呃，又這樣？難怪還沒接起來就斷了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우리가 없는 틈에 먹비 한 방울 없이 장치가 작동하다니. 참으로 공교롭군.","JPN":"我らがいない間に墨雨もなしに装置が稼働するとは……あいにくだったな。","ENG":"So the device activated without a drop of Ink Rain while we were gone. What a coincidence.","TWN":"我們不在的時候，裝置竟然能在沒有墨雨的情況下運作。真是巧合。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그러게. 하필 모두 자릴 비웠을 때 작동하는 건 좀 억울하네.","JPN":"ほんと。よりによって誰も居ない時に動いちゃうなんて、ちょっと悔しいよね。","ENG":"Right? Of all times, it had to be when no one was watching. That's just unfair.","TWN":"是啊。偏偏在我們都不在的時候啟動，也太讓人鬱悶了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그래도 우물이 멀쩡히 작동한다는 사실을 확인한 건 좋은 소식일세.","JPN":"だが、井戸が正常に稼働すると確認できたのは収穫だ。","ENG":"Still, confirming the well can function properly is good news.","TWN":"不過，確認那口井能正常運作，是個好消息。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우리 기억을 되짚다 보면 무엇이 우물을 가동한 원인인지 찾을 수 있을 지도 모르지.","JPN":"全員の記憶を辿ってみれば、井戸を稼働させた原因が何か突き止められるかもしれん。","ENG":"If we retrace our steps, we might be able to figure out what triggered it.","TWN":"如果我們回想一下，或許能找到是什麼原因啟動了那口井。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"우린 이곳에서 침식체를 잡았어.","JPN":"私たちはここで侵食体を倒した。","ENG":"We took down a C.O. here.","TWN":"我們在這裡殺了侵蝕體。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"큰 녀석이니까, 그만큼 큰 이터니움을 품고 있었던 걸지도 모르지.","JPN":"デカいやつだったから、それに見合うだけのエタニウムを持っていたのかもしれない。","ENG":"It was a big one. Probably packed with a ton of Eternium.","TWN":"是個大塊頭，說不定它身上有大量的永恆之金。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"우물이 부족한 동력원을 침식체한테 흡수해서 작동했다는 거야?","JPN":"井戸が、足りない動力源を侵食体から吸い取って動いたってこと？","ENG":"You think the well used the C.O. as a power source?","TWN":"你是說，那口井吸收了侵蝕體，補充了不足的動力才啟動的嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"가설은 많을수록 좋지. 다른 짚이는 점은 없나?","JPN":"仮説は多いほどいい。他に思い当たるところはないか？","ENG":"The more theories, the better. Anything else come to mind?","TWN":"假設越多越好。還有別的線索嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 뒤론 별일 없었다.","JPN":"その後は特に何も起こらなかった。","ENG":"Nothing worth mentioning after that.","TWN":"之後就沒什麼特別的事了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"침식체의 핵을 벤 당신은 피를 토하며 쓰러졌고, 그대로 도시의 병원으로 옮겨졌지.","JPN":"侵食体のコアを斬ったお前は血を吐いて倒れ、そのまま都市の病院に運ばれていった。","ENG":"After you struck the C.O.'s core, you collapsed coughing up blood. We rushed you to a hospital in the city.","TWN":"你斬了侵蝕體的核心後吐血倒下，然後被送到了城裡的醫院。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"우리가 자릴 비운 하루 사이에 다른 어떤 일이 있었는진 몰라.","JPN":"私たちが居なかった1日の間に何があったかまでは分からない。","ENG":"Whatever happened while we were gone, no one knows.","TWN":"我們離開的這一天裡，還有沒有發生其他事，我們就不知道了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_SILHOUETTE","text":{"KOREA":"그 누구도 지나간 일을 돌이키지 못해.","JPN":"過ぎたことは誰にも取り戻せないわ。","ENG":"No one can undo what's already passed.","TWN":"沒有任何人，能讓過去的事情重來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_SILHOUETTE","text":{"KOREA":"하지만 당신은 다르잖아. 특별한 피를 가졌으니까.","JPN":"でもあなたは違う。特別な血を持っているもの。","ENG":"But you're different. You carry a special bloodline.","TWN":"但你不同。你擁有特殊的血。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그런 거였군.","JPN":"……そういうことか。","ENG":"…So that's what it was.","TWN":"…原來如此。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"땅내림… 범… 그리고 먹비.","JPN":"チガカリ……虎……そして墨雨。","ENG":"Earthbound… the Tiger… and the Ink Rain.","TWN":"地脈之力…老虎…還有墨雨。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이 모든 것과 연관성을 가진 하나가 이렇게 가까이에 있었는데도 몰랐다니.","JPN":"このすべてと関わりを持つものが、こうも近くに在ったにも関わらず気がつかないとは。","ENG":"Everything connected to them was right here under my nose, and I failed to see it.","TWN":"一個與所有這些都有關聯的存在，就在我身邊，我卻一直不知道。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아앗?! 갑자기 뭐하는 거야, 사부?","JPN":"ああ！？　いきなり何するの、師匠！","ENG":"Huh?! What are you doing, Master?!","TWN":"啊？！師父你突然幹什麼？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"왜 자기 팔에 상처를 내는 건데?!","JPN":"なんで自分の腕に傷をつけるの！？","ENG":"Why would you cut your own arm?!","TWN":"為什麼要割自己的手臂？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"우물에서… 다시 빛이…?","JPN":"井戸から……また光が……？","ENG":"The well… is glowing again…?","TWN":"井裡…又發光了？"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"설마, 사부가 흘린 피 때문에?","JPN":"まさか、師匠の血のせい？","ENG":"Wait, is it because of your blood?!","TWN":"難道，是因為師父流出的血？"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"과거에 몸을 두 번이나 담근 영향이었을까…","JPN":"過去を2度も経験したせいか……","ENG":"Could it be the side effect of bathing in that light twice…","TWN":"是因為兩次將身體沉浸在過去的影響嗎…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"오래 전 가라앉은 기억들이 잠결에 조각조각 떠오르더군.","JPN":"遥か昔に沈んでいた記憶の破片が、夢うつつの合間から浮上してきた。","ENG":"Memories long buried started surfacing again in fragments.","TWN":"很久以前沉澱的記憶，在睡夢中一片片地浮現。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그래. 진작에 눈치를 채야 했어.","JPN":"ああ、もっと早く気付くべきだったのだ。","ENG":"Of course. I should've realized it sooner.","TWN":"對。我早就該察覺到的。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이 몸에 흐르는 피가…","JPN":"この身に流れる血が……","ENG":"The blood that runs through me…","TWN":"流淌在我身體裡的血…"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그날의 하늘을 아우르던 까마득한 먹빛과 닮았다는 것을.","JPN":"あの日の空を覆っていた、墨の色に似ているということに。","ENG":"is the same color as that sky-dimming ink-black I saw that day.","TWN":"和那天籠罩天空的漆黑墨雨，是如此地相似。"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부?","JPN":"師匠？","ENG":"Master?","TWN":"師父？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어르신! 사부가 사라졌어! 어떻게 된 거지?","JPN":"おばあさん！　師匠が消えちゃった！　ど、どうしよ！","ENG":"Granny! Master's gone! What just happened?!","TWN":"阿姨！師父不見了！發生了什麼事？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"진정해, 앤디.","JPN":"落ち着け、アンディー。","ENG":"Calm down, Andy.","TWN":"冷靜點，安狄。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"방금 전 우물의 빛이 사라지면서 하늘도 변했다.","JPN":"さっき井戸の光が消えると同時に空が変わった。","ENG":"The moment that light from the well vanished, the sky changed too.","TWN":"剛才井裡的光芒消失時，天空也改變了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"여긴… 우리가 원래 있던 곳이 아니야.","JPN":"ここは……私たちが元いた場所ではない。","ENG":"This… isn't where we were a minute ago.","TWN":"這裡…不是我們原來的地方。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그러고보니 나무들 키가 엄청 커지지 않았어? 종류도 바뀐 것 같아.","JPN":"そういえば、周りの木がなんかデカくなってない？　種類も変わった気がする。","ENG":"Now that you mention it, the trees are way taller. And they look different.","TWN":"說起來，樹木是不是變得很高？種類也變了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"저것들은 아마도… 서생이 말한 소귀나무라는 거겠지.","JPN":"あれは多分……ショウが言っていた、ヤマモモの木というやつだろう。","ENG":"Those might be… the waxberry trees Seosaeng mentioned.","TWN":"那些大概是…書生說的楊梅樹吧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"소귀나무? 그럼 지금 우리가 있는 곳이…?","JPN":"ヤマモモの木？　じゃあ、今私たちがいる場所って……？","ENG":"Waxberry trees? Then that means this forest is…","TWN":"楊梅樹？那我們現在是在…？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"길이라도 잃은 게냐?","JPN":"道に迷ったのか？","ENG":"Lost your way, have you?","TWN":"你迷路了嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"앗, 사람이다.","JPN":"あっ、人だ。","ENG":"Ah, someone's here.","TWN":"啊，有人。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"전에 봤던 언니가 아닌데, 누구지?","JPN":"この前見たお姉さんじゃない。誰だろう？","ENG":"He's not Yeonhwa… Who is he?","TWN":"不是之前見過的那位姊姊，是誰？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신… 그 눈.","JPN":"お前……その目は。","ENG":"You… those eyes.","TWN":"你…那雙眼睛。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"허허, 아주 뚫어져라 노려보는구나.","JPN":"はは、なかなかの目つきだな。","ENG":"Haha. Staring a hole right through me, aren't you?","TWN":"呵呵，怎麼直盯著人看呢。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이 안대에 관심이라도 있느냐?","JPN":"この眼帯に興味があるのか？","ENG":"You interested in this eye patch or something?","TWN":"對我的眼罩有興趣嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신이었어.","JPN":"お前だったんだな。","ENG":"It was you.","TWN":"是你。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"휴우.","JPN":"ふう……","ENG":"Whew.","TWN":"呼。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"물은 찾았지만, 생각보다 멀리 와버렸네.","JPN":"水は見つかったものの、思ったより遠くまで来てしまったわ。","ENG":"I found the water, but I've wandered farther than I expected.","TWN":"找到水了，但沒想到有點遠。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"적당히 시원하고… 역시 세수만 하는 건 아깝지?","JPN":"涼しくて……やっぱり顔を洗うだけじゃもったいないわね。","ENG":"It's cool… feels like a waste to only wash my face.","TWN":"水真涼快，好舒服…只洗臉有點可惜呢？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Mm?","TWN":"嗯…？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"명달 대장…?","JPN":"アカタツ隊長なんですか……？","ENG":"Commander Myeongdal…?","TWN":"是明達隊長嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"눈이 침침하네. 내가 헛것이 보이나?","JPN":"目がどうかしてるのかしら？　幻が見えるわ。","ENG":"Must be my eyes. Am I seeing a ghost?","TWN":"我是看到幻覺嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"헛것이 아닐세.","JPN":"幻ではない。","ENG":"You're not.","TWN":"不是幻覺。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신이 왜 여기 있는 거야?","JPN":"どうしてあなたがここにいるの？","ENG":"What are you doing here?","TWN":"你為什麼會在這裡？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"오히려 내가 묻고 싶군.","JPN":"こちらこそ聞きたいものだ。","ENG":"I should be asking you that.","TWN":"反而是我想問你。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나를 남겨두고 그대 혼자 이곳에 온 이유를.","JPN":"某を置いて、そなた一人でここに来た理由を。","ENG":"Why did you come here without me?","TWN":"為什麼把我留在原地，你一個人來到這裡。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"으응…?","JPN":"うん……？","ENG":"Hmm…?","TWN":"嗯嗯…？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신. 내가 목욕하는 게 그 정도로 보고 싶었어?","JPN":"あなた、私が水浴びしてるところがそんなに見たかったの？","ENG":"What, you really wanted to see me bathing that badly?","TWN":"你，就那麼想看我洗澡嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"연화! 난 그런 의미가 아니라…","JPN":"レンカ！　そういう意味ではなく……","ENG":"Yeonhwa! That's not what I mea–","TWN":"蓮華！我不是那個意思…"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신도 알고 있잖아.","JPN":"あなたも分かっているでしょう。","ENG":"You know as well as I do.","TWN":"你也知道吧。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"땅내림을 받은 사람은 반드시 끝이 좋지 않다는 걸.","JPN":"チガカリを受け継いだ者が、どんな末路を迎えるのか。","ENG":"Anyone Earthbound never meets a happy end.","TWN":"擁有地脈之力天賦的人，結局都不會好。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그 땅내림을 받았기에, 짐승에게 대적할 힘이 있어.","JPN":"でも、そのチガカリを受け継いだからこそ、この力でケモノと戦える。","ENG":"But that same curse gives us the strength to fight the Beasts.","TWN":"但正是因為擁有地脈之力天賦，我們才有對抗野獸的力量。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러니, 이게 내가 짊어져야 할 운명이야.","JPN":"だから、これは私が背負うべき運命よ。","ENG":"So, this is my fate to carry.","TWN":"所以，這是我的命運，我必須要承擔。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"땅내림을 받은 건 나 또한 마찬가지요! 그런데 어째서 혼자 짊어지겠다고만 말하는가!","JPN":"チガカリを受け継いでいるのは某も同じだ！　なのになぜ一人で背負うと言うのだ！","ENG":"I am Earthbound too! So why do you insist on doing this alone?!","TWN":"擁有地脈之力天賦的我也一樣！但為什麼你總是一個人說要承擔一切！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그야 당신의 도움 같은 건 필요하지 않으니까!","JPN":"あなたの助けなんか要らないからよ！","ENG":"Because I don't need your help!","TWN":"因為我不需要你的幫助！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그 말이 진심이라면, 그 이유를 들어야겠소.","JPN":"……それが本当なら、その理由を聞かせてくれ。","ENG":"…If you truly mean that, then I want to hear your reason.","TWN":"…如果你是真心話，那我要聽聽理由。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신은 아무것도 몰라, 서생.","JPN":"あなたは何も知らないのよ、ショウ。","ENG":"You know nothing, Seosaeng.","TWN":"書生，你什麼都不知道。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그리고 아무것도 모르는 편이 좋아.","JPN":"そして、何も知らない方がいい。","ENG":"And it's better that way.","TWN":"而且你最好什麼都不知道。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"나를 위해서가 아니라… 우리 모두를 위해서 하는 말이야.","JPN":"私のためじゃなくて……私たちみんなのために。","ENG":"Not for my sake… but for all of ours.","TWN":"這不是為了我…是為了我們所有人。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나 또한 범을 잡는 삼군문 별동대의 일원이 아니던가!","JPN":"某も虎を倒す三軍門別働隊の一員ではないか！","ENG":"I'm also a member of Trivanguard hunting the Tiger, am I not?!","TWN":"我難道不是抓捕老虎的三軍門先鋒隊成員嗎！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내가 그 짐승과 맞서지 못할 만큼 나약하다 생각하는 거요?","JPN":"某があのケモノに太刀打ちできないほど弱いと思っているのか？","ENG":"Do you really think I'm too weak to face that Beast?","TWN":"你覺得我弱到無法對抗那隻野獸嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그것도 틀린 말은 아니네.","JPN":"それもあるわね。","ENG":"You're not exactly wrong.","TWN":"這話也沒錯。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"난 당신보다 압도적으로 강하니까. 나한테 당신은 걸림돌일 뿐이야.","JPN":"私はあなたより圧倒的に強い。あなたなんて、足手まといに過ぎないわ。","ENG":"I'm far stronger than you. You'd only hold me back.","TWN":"我比你強得多。對我來說，你只會是絆腳石。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그렇다면 합을 치러 보세.","JPN":"なら、手合わせをしてみようではないか。","ENG":"Then let's settle this with our blades.","TWN":"那我們較量一番吧。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내가 그대를 이길 만큼 강하단 걸 입증한다면… 우린 함께 싸우는 거요.","JPN":"某がそなたに勝てるほど強いと証明できれば……一緒に戦おう。","ENG":"If I prove I'm strong enough to beat you… then we fight together.","TWN":"如果我能證明我強大到能打敗你…我們就一起戰鬥。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"빨리 끝내자.","JPN":"早く終わらせましょう。","ENG":"Fine. Let's get this over with.","TWN":"快點結束吧。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"지면 군말 없이 돌아가줘.","JPN":"負けたら文句言わずに帰ってちょうだい。","ENG":"But if you lose, you go back without another word.","TWN":"如果你輸了，就乖乖回去。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};